import java.util.Scanner;

public class SecureBufferOverflow {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a maximum buffer size to prevent overflow
        int bufferSize = 10;

        // Truncate input if it exceeds the buffer size
        if (name.length() > bufferSize) {
            name = name.substring(0, bufferSize);
        }

        // Copy the validated user input into the buffer
        char[] buffer = new char[bufferSize];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Name entered: " + new String(buffer));
    }
}

